select 
from discuss_post
where status != 2

    and user_id = #{userId, jdbcType=BINARY}


    and category_id = #{categoryId, jdbcType=BINARY}


    and category_id in

        #{cid, jdbcType=BINARY}



    and exists (
        select 1
        from post_tag pt
        join tag t on pt.tag_id = t.id
        where pt.post_id = discuss_post.id
          and t.name = #{tag}
    )


    order by type desc, create_time desc


    order by type desc, score desc, create_time desc

limit #{offset}, #{limit}

select 
from discuss_post
where status != 2

  and id > #{afterId, jdbcType=BINARY}

order by id asc
limit #{limit}

select from discuss_post where status = 0 and user_id in
#{authorId, jdbcType=BINARY}
order by create_time desc, id desc limit #{limit}

select 
from discuss_post
where status = 0
  and user_id in

      #{authorId, jdbcType=BINARY}

  and (
      create_time < #{beforeCreateTime}
      or (create_time = #{beforeCreateTime} and id < #{beforePostId, jdbcType=BINARY})
  )
order by create_time desc, id desc
limit #{limit}

select 
from discuss_post
where id = #{id, jdbcType=BINARY}

mapper.update:
update discuss_post
set comment_count = coalesce(comment_count, 0) + #{delta}
where id = #{id, jdbcType=BINARY}

update discuss_post
set status = #{status},
    deleted_by = #{deletedBy, jdbcType=BINARY},
    deleted_reason = #{deletedReason},
    deleted_time = #{deletedTime}
where id = #{id, jdbcType=BINARY}
  and status != #{status}
